import React from 'react';
import { render, screen } from '@testing-library/react';
import { renderHook, act } from '@testing-library/react';
import { useDungeonSessionManager } from '../dungeon-use-session-manager';
import { useTreasureSearch } from '../dungeon-use-treasure';
import DungeonInventoryModal from '../dungeon-inventory-modal';

// Mock the visibility calculator to deterministically return the hero's cell as visible
jest.mock('../dungeon-use-visibility-calc', () => ({
  useVisibilityCalc: () => ({
    calculateVisibleCells: (x, y) => [{ x, y }]
  })
}));

describe('LootInventoryRegression', () => {

  describe('Scenario: Treasure Card Notification Uses Human Label', () => {
    it('resolves and shows human-readable label or fallback to raw numeric ID', () => {
      const onNotify = jest.fn();
      const onUpdateSession = jest.fn();
      const staticItems = [{ id: 101, nome: 'Pozione', descrizione: 'Pozione Curativa' }];
      const staticEquipment = [{ id: 201, nome: 'Spada', descrizione: 'Spada Lunga' }];
      
      const gameSession = {
        heroes: [{ heroId: 1, inventory: [], equipment: [], gold: 0, currentBody: 10 }]
      };

      const { result } = renderHook(() => useDungeonSessionManager({
        gameSession,
        onUpdateSession,
        onNotify,
        fogOfWarLogic: { revealFromPoint: jest.fn(), revealInitialVisibility: jest.fn() },
        staticEquipment,
        staticItems
      }));

      const cardItem = { azione: 'aggiungi_oggetto', valore: 101 };
      const cardEquip = { azione: 'aggiungi_oggetto', valore: 201 };
      const cardUnknown = { azione: 'aggiungi_oggetto', valore: 999 };

      act(() => {
        result.current.applyTreasureCardEffect(1, cardItem, jest.fn());
      });
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('Pozione Curativa'));

      act(() => {
        result.current.applyTreasureCardEffect(1, cardEquip, jest.fn());
      });
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('Spada Lunga'));

      act(() => {
        result.current.applyTreasureCardEffect(1, cardUnknown, jest.fn());
      });
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('ID 999'));
    });
  });

  describe('Scenario: Map Treasure Notification Uses Human Label', () => {
    it('uses resolved human label and does not regress to ID-only text', () => {
      const onNotify = jest.fn();
      let currentSession = {
        heroes: [{ heroId: 1, inventory: [], equipment: [], equipped: [], gold: 0, currentBody: 10 }],
        currentMap: {
          grid: [
            { x: 0, y: 0, tes: { mon: 0, ogg: 101, arma: 201, trp: 0 } },
            { x: 1, y: 1, tes: { mon: 0, ogg: 999, arma: 888, trp: 0 } }
          ]
        }
      };
      
      // Simulate React state updater behavior synchronously for the test
      const onUpdateSession = jest.fn((updater) => {
        currentSession = updater(currentSession);
      });
      
      const staticItems = [{ id: 101, nome: 'Pozione', descrizione: 'Pozione Curativa' }];
      const staticEquipment = [{ id: 201, nome: 'Spada', descrizione: 'Spada Lunga' }];

      const { result } = renderHook(() => useDungeonSessionManager({
        gameSession: currentSession,
        onUpdateSession,
        onNotify,
        fogOfWarLogic: { revealFromPoint: jest.fn(), revealInitialVisibility: jest.fn() },
        staticEquipment,
        staticItems
      }));

      act(() => {
        result.current.collectTreasureAtCell(1, 0, 0);
      });
      
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('Pozione Curativa'));
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('Spada Lunga'));

      act(() => {
        result.current.collectTreasureAtCell(1, 1, 1);
      });
      
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('ID 999'));
      expect(onNotify).toHaveBeenCalledWith(expect.stringContaining('ID 888'));
    });
  });

  describe('Scenario: Inventory Modal Resolves Equipment Names', () => {
    it('renders equipment with resolved label and uses localized fallback if missing', () => {
      const hero = {
        hero: { nome: 'Guerriero', classe: 'Combattente', immagine: 'guerriero.png' },
        gold: 100,
        inventory: [],
        equipment: [201, 999]
      };
      const allEquipment = [{ id: 201, nome: 'Spada', descrizione: 'Spada Lunga' }];

      render(<DungeonInventoryModal isOpen={true} hero={hero} allItems={[]} allEquipment={allEquipment} onClose={jest.fn()} />);

      expect(screen.getByText('Spada Lunga')).toBeInTheDocument();
      expect(screen.getByText('Equipaggiamento ID 999')).toBeInTheDocument();
      expect(screen.queryByText(/Unknown equipment/i)).not.toBeInTheDocument();
    });
  });

  describe('Scenario: Inventory Modal Resolves Item Names', () => {
    it('renders item labels with resolved nome/descrizione and uses localized fallback if missing', () => {
      const hero = {
        hero: { nome: 'Mago', classe: 'Incantatore', immagine: 'mago.png' },
        gold: 50,
        inventory: [101, 888],
        equipment: []
      };
      const allItems = [{ id: 101, nome: 'Pozione', descrizione: 'Pozione Curativa' }];

      render(<DungeonInventoryModal isOpen={true} hero={hero} allItems={allItems} allEquipment={[]} onClose={jest.fn()} />);

      expect(screen.getByText('Pozione Curativa')).toBeInTheDocument();
      expect(screen.getByText('Oggetto ID 888')).toBeInTheDocument();
      expect(screen.queryByText(/Unknown Item/i)).not.toBeInTheDocument();
    });
  });

  describe('Scenario: Empty Designated Map Treasure Square Notifies And Skips Deck', () => {
    it('notifies empty treasure, skips deck, and does not invoke collectTreasureAtCell', () => {
      const onNotify = jest.fn();
      const onActionDone = jest.fn();
      const onForceTurnEnd = jest.fn();
      const onTreasureCardDrawn = jest.fn();
      const onWanderingMonster = jest.fn();
      
      const gameSession = {
        monsters: [],
        heroes: [{ heroId: 1, turnOrder: 1, x: 5, y: 5 }],
        currentTurn: 1,
        currentMap: {
          grid: [
            { x: 5, y: 5, tes: { ts: 1, mon: 0, ogg: 0, arma: 0, trp: 0 } }
          ]
        },
        treasureDeck: [{ azione: 'aggiungi_oro', valore: 100 }]
      };

      const sessionManager = {
        executeMissionScripts: jest.fn().mockReturnValue({ handled: false }),
        collectTreasureAtCell: jest.fn(),
        drawTreasureCard: jest.fn()
      };

      const visibilityMap = {
        data: [
          { x: 5, y: 5, visible: true }
        ]
      };

      const { result } = renderHook(() => useTreasureSearch({
        gameSession,
        visibilityMap,
        onNotify,
        onActionDone,
        onForceTurnEnd,
        sessionManager,
        onTreasureCardDrawn,
        onWanderingMonster
      }));

      act(() => {
        result.current.searchTreasure();
      });

      expect(onNotify).toHaveBeenCalledWith('Il tesoro è vuoto.');
      expect(sessionManager.drawTreasureCard).not.toHaveBeenCalled();
      expect(sessionManager.collectTreasureAtCell).not.toHaveBeenCalled();
    });
  });

});